sonb, 296000, 'KRW', true, '{"source": "enclosures.json"}'::jsonb) ON CONFLICT (sku) DO NOTHING;\n\n-- ACCESSORIES\n\nINSERT INTO shared.catalog_items (kind, sku, name, spec, unit_price, currency, is_active, meta) VALUES ('accessory_rules', 'ACC-RULES-V1.0.0', 'Accessories Rules v1.0.0 (CEO Signed)', '{"magnets": {}, "timers": {}, "bom_bundles": {}, "layout_rules": {"PBL": "도어 전면 설치, 마그네트 존재 시만 설치, D 증가 요인", "단자대": "외함 하단 설치, 단자 간 이격 유지", "마그네트": "차단기 하단 또는 여유공간 설치, 발열 간격 확보"}, "magnet_layout": {"title": "마그네트 외함 배치 기준", "description": "마그네트 용량에 따라 외함 W별 최대 수용 개수 규칙", "rules": [{"magnet_range": "MC-12 ~ MC-22", "base_enclosure_width": 600, "base_count": 5, "increment_per_100mm": 2}, {"magnet_range": "MC-30 ~ MC-42", "base_enclosure_width": 600, "base_count": 4, "increment_per_100mm": 1}], "example": {"W=800mm": {"MC-18a": "5 + ((800-600)//100)×2 = 9EA", "MC-32a": "4 + ((800-600)//100)×1 = 6EA"}}, "height_adjustment_rule": [{"magnet_range": "MC-12 ~ MC-22", "condition": "1EA", "height_increase_mm": 0, "note": "메인 좌우 여유 공간에 배치, H 증가 없음"}, {"magnet_range": "MC-12 ~ MC-22", "condition": "2EA 이상", "height_increase_mm": 250, "note": "1줄로 배치 시 H +250"}, {"magnet_range": "MC-30 ~ MC-42", "condition": "1EA 이상", "height_increase_mm": 300, "note": "외함 H +300"}]}, "pbl_dependency": {"rule": "PBL은 마그네트 회로 존재 시 선택적으로 따라오며, 단독으로는 절대 포함되지 않음"}}'::jsonb, 0, 'KRW', true, '{"source": "accessories.json", "signed_by": "CEO"}'::jsonb) ON CONFLICT (sku) DO NOTHING;\n\n-- FORMULAS\n\nINSERT INTO shared.catalog_items (kind, sku, name, spec, unit_price, currency, is_active, meta) VALUES ('formulas', 'FORMULA-V1.0.0', 'Calculation Formulas v1.0.0', '{"enclosure": {"W_total": {"100AF": 600, "125-250AF": 700, "400AF": 800, "600AF+": 900}, "H_total": {"top_margin": {"100AF": 130}, "bottom_margin": {"100AF": 100}, "per_breaker_row": 100, "per_magnet_row": 70, "per_terminal_row": 50}, "D_total": {"default": 200, "if_PBL": 250}}, "busbar": {"weight_kg": "(W*H) * coefficient", "coefficient": {"20-250A": 7e-06, "300-400A": 1.3e-05, "500-800A": 1.5e-05}, "price_per_kg": 20000}}'::jsonb, 0, 'KRW', true, '{"source": "formulas.json"}'::jsonb) ON CONFLICT (sku) DO NOTHING;\n\n-- STANDARDS\n\nINSERT INTO shared.catalog_items (kind, sku, name, spec, unit_price, currency, is_active, meta) VALUES ('standards', 'STANDARDS-V1.0.0', 'IEC61439 + KS C 4510', '{"IEC61439": {"clearance_creepage": {"description": "Air clearance and creepage distances per IEC 61439-1 Table 1", "pollution_degree_2": {"50V": {"clearance_mm": 0.2, "creepage_mm": 0.4}, "125V": {"clearance_mm": 0.5, "creepage_mm": 1.25}, "250V": {"clearance_mm": 1.5, "creepage_mm": 2.5}, "500V": {"clearance_mm": 3.0, "creepage_mm": 5.0}, "690V": {"clearance_mm": 4.0, "creepage_mm": 6.3}, "1000V": {"clearance_mm": 5.5, "creepage_mm": 8.0}}, "pollution_degree_3": {"50V": {"clearance_mm": 0.2, "creepage_mm": 0.8}, "125V": {"clearance_mm": 0.5, "creepage_mm": 2.5}, "250V": {"clearance_mm": 1.5, "creepage_mm": 4.0}, "500V": {"clearance_mm": 3.0, "creepage_mm": 8.0}, "690V": {"clearance_mm": 4.0, "creepage_mm": 10.0}, "1000V": {"clearance_mm": 5.5, "creepage_mm": 12.5}}}, "temp_rise_design": {"description": "Temperature rise limits per IEC 61439-1 Table 4", "conductor_connections": {"bare_copper": {"max_temp_c": 105, "max_rise_k": 70}, "insulated_copper": {"max_temp_c": 90, "max_rise_k": 55}, "silver_plated": {"max_temp_c": 105, "max_rise_k": 70}}, "accessible_parts": {"metallic_parts": {"max_rise_k": 30}, "insulating_parts": {"max_rise_k": 40}}}, "short_circuit_withstand": {"description": "Short-circuit withstand requirements per IEC 61439-1", "test_conditions": {"peak_current_factor": 2.5, "power_factor": 0.15, "asymmetry_factor": 1.8, "test_duration_s": 1.0}, "verification_methods": ["testing", "comparison_with_tested_assembly", "calculation"]}, "protective_circuit": {"description": "Protective conductor requirements per IEC 61439-1", "min_cross_section": {"up_to_16mm2": "equal_to_line", "16_to_35mm2": "16mm2_min", "above_35mm2": "half_line_conductor"}, "connection_requirements": {"bolted_connection": {"min_bolts": 2, "torque_factor": 0.8, "material": "copper_or_equivalent"}}}, "ip_degree": {"description": "IP degree requirements per IEC 60529", "enclosure_types": {"IP20": {"protection": "finger_safe", "min_opening_mm": 12.5}, "IP30": {"protection": "tool_safe", "min_opening_mm": 2.5}, "IP40": {"protection": "wire_safe", "min_opening_mm": 1.0}, "IP54": {"protection": "dust_limited", "water": "splash_proof"}, "IP55": {"protection": "dust_limited", "water": "jet_proof"}, "IP65": {"protection": "dust_tight", "water": "jet_proof"}}}}, "KS_C_4510": {"labels_marking": {"description": "Required labels and marking per KS C 4510", "mandatory_labels": {"nameplate": {"required_info": ["manufacturer_name", "model_designation", "serial_number", "year_of_manufacture", "rated_voltage", "rated_current", "rated_frequency", "ip_degree", "short_circuit_rating"], "material": "durable_engraved_or_printed", "location": "visible_accessible"}, "warning_labels": {"electrical_hazard": {"text_ko": "위험! 고전압", "text_en": "DANGER! HIGH VOLTAGE", "symbol": "IEC_60417_5036", "color": "red_on_yellow"}, "arc_flash": {"text_ko": "경고! 아크 플래시 위험", "text_en": "WARNING! ARC FLASH HAZARD", "required_when": "above_240V"}}}}, "wiring_color_code": {"description": "Wire color coding per KS C IEC 60446", "ac_circuits": {"single_phase": {"line": "brown_or_black", "neutral": "blue", "protective_earth": "green_yellow"}, "three_phase": {"L1": "brown", "L2": "black", "L3": "gray", "neutral": "blue", "protective_earth": "green_yellow"}}, "dc_circuits": {"positive": "brown_or_red", "negative": "blue_or_black", "protective_earth": "green_yellow"}}, "enclosure_requirements": {"description": "Enclosure requirements per KS C 4510", "material_requirements": {"metallic_enclosures": {"min_thickness_mm": {"steel_sheet": 1.5, "aluminum_sheet": 2.0, "stainless_steel": 1.2}, "surface_treatment": "corrosion_resistant"}, "non_metallic_enclosures": {"flame_rating": "V0_or_better", "uv_resistance": "required_for_outdoor", "impact_resistance": "IK08_minimum"}}}, "installation_requirements": {"description": "Installation requirements per KS C 4510", "mounting": {"wall_mount": {"min_clearance_top_mm": 200, "min_clearance_bottom_mm": 100, "min_clearance_sides_mm": 150}, "floor_mount": {"min_clearance_front_mm": 800, "min_clearance_rear_mm": 600, "min_clearance_sides_mm": 200}}, "ventilation": {"natural_ventilation": {"inlet_area_factor": 1.0, "outlet_area_factor": 1.3}, "forced_ventilation": {"air_change_rate_min": 10}}}}}'::jsonb, 0, 'KRW', true, '{"source": "standards.json"}'::jsonb) ON CONFLICT (sku) DO NOTHING;\n\n-- TOTAL: 276 records\n